onClick:
{{
InsertRiskSelection.run()
.then(res => {

  if (res?.[0]?.Status === "EXISTS") {
    showAlert("Risk already exists", "warning");
    return;
  }

  return GetRiskSelection.run()
  .then(() => {

    const index = appsmith.store.riskRowIndex;
    const newRisk = Input_NewRisk.text;

    const data = [...Table_High_Low.tableData];

    if (index !== undefined && data[index]) {
      data[index].Risk = newRisk;
      Table_High_Low.setData(data);
    }

    closeModal(Modal_AddRisk.name);
    showAlert("Risk added", "success");

  });

})
}}
